#!/usr/bin/env python3\n\"\"\"\nTo-Do List Application with Local Storage\nAuthor: bio-computerinteranthusasum786\nVersion: 1.0.0\n\nA simple yet powerful to-do list application that stores tasks locally\nusing JSON format for easy persistence and retrieval.\n\"\"\"\n\nimport json\nimport os\nfrom datetime import datetime\nfrom pathlib import Path\nfrom typing import List, Dict, Optional, Any\nimport uuid\n\n\nclass TodoItem:\n    \"\"\"Represents a single to-do item\"\"\"\n\n    def __init__(\n        self,\n        title: str,\n        description: str = \"\",\n        priority: str = \"medium\",\n        due_date: Optional[str] = None,\n        task_id: Optional[str] = None,\n        completed: bool = False,\n        created_at: Optional[str] = None,\n        completed_at: Optional[str] = None,\n        tags: Optional[List[str]] = None,\n    ):\n        self.id = task_id or str(uuid.uuid4())\n        self.title = title\n        self.description = description\n        self.priority = priority.lower()  # low, medium, high, urgent\n        self.due_date = due_date\n        self.completed = completed\n        self.created_at = created_at or datetime.now().isoformat()\n        self.completed_at = completed_at\n        self.tags = tags or []\n\n    def mark_complete(self):\n        \"\"\"Mark task as completed\"\"\"\n        self.completed = True\n        self.completed_at = datetime.now().isoformat()\n\n    def mark_incomplete(self):\n        \"\"\"Mark task as incomplete\"\"\"\n        self.completed = False\n        self.completed_at = None\n\n    def to_dict(self) -> Dict[str, Any]:\n        \"\"\"Convert to dictionary for JSON serialization\"\"\"\n        return {\n            \"id\": self.id,\n            \"title\": self.title,\n            \"description\": self.description,\n            \"priority\": self.priority,\n            \"due_date\": self.due_date,\n            \"completed\": self.completed,\n            \"created_at\": self.created_at,\n            \"completed_at\": self.completed_at,\n            \"tags\": self.tags,\n        }\n\n    @staticmethod\n    def from_dict(data: Dict[str, Any]) -> \"TodoItem\":\n        \"\"\"Create TodoItem from dictionary\"\"\"\n        return TodoItem(\n            title=data[\"title\"],\n            description=data.get(\"description\", \"\"),\n            priority=data.get(\"priority\", \"medium\"),\n            due_date=data.get(\"due_date\"),\n            task_id=data.get(\"id\"),\n            completed=data.get(\"completed\", False),\n            created_at=data.get(\"created_at\"),\n            completed_at=data.get(\"completed_at\"),\n            tags=data.get(\"tags\", []),\n        )\n\n    def __str__(self) -> str:\n        status = \"✓\" if self.completed else \"○\"\n        priority_emoji = {\n            \"low\": \"🟢\",\n            \"medium\": \"🟡\",\n            \"high\": \"🔴\",\n            \"urgent\": \"🔴🔴\",\n        }.get(self.priority, \"🟡\")\n\n        result = f\"{status} [{priority_emoji}] {self.title}\"\n        if self.due_date:\n            result += f\" (Due: {self.due_date})\"\n        if self.tags:\n            result += f\" #{', #'.join(self.tags)}\"\n        return result\n\n\nclass TodoList:\n    \"\"\"Manages a list of to-do items with local storage\"\"\"\n\n    def __init__(self, storage_file: str = \"todos.json\"):\n        self.storage_file = Path(storage_file)\n        self.tasks: Dict[str, TodoItem] = {}\n        self.load_from_storage()\n\n    # ==================== FILE OPERATIONS ====================\n\n    def load_from_storage(self) -> bool:\n        \"\"\"Load tasks from local storage\"\"\"\n        if not self.storage_file.exists():\n            return False\n\n        try:\n            with open(self.storage_file, \"r\") as f:\n                data = json.load(f)\n                self.tasks = {\n                    task[\"id\"]: TodoItem.from_dict(task) for task in data\n                }\n            return True\n        except (json.JSONDecodeError, KeyError, IOError) as e:\n            print(f\"Error loading tasks: {e}\")\n            return False\n\n    def save_to_storage(self) -> bool:\n        \"\"\"Save tasks to local storage\"\"\"\n        try:\n            tasks_data = [task.to_dict() for task in self.tasks.values()]\n            with open(self.storage_file, \"w\") as f:\n                json.dump(tasks_data, f, indent=2)\n            return True\n        except IOError as e:\n            print(f\"Error saving tasks: {e}\")\n            return False\n\n    def export_to_file(self, filename: str) -> bool:\n        \"\"\"Export tasks to a specific file\"\"\"\n        try:\n            tasks_data = [task.to_dict() for task in self.tasks.values()]\n            with open(filename, \"w\") as f:\n                json.dump(tasks_data, f, indent=2)\n            return True\n        except IOError as e:\n            print(f\"Error exporting tasks: {e}\")\n            return False\n\n    def import_from_file(self, filename: str) -> bool:\n        \"\"\"Import tasks from a file\"\"\"\n        try:\n            with open(filename, \"r\") as f:\n                data = json.load(f)\n                for task_data in data:\n                    task = TodoItem.from_dict(task_data)\n                    self.tasks[task.id] = task\n            self.save_to_storage()\n            return True\n        except (json.JSONDecodeError, IOError, KeyError) as e:\n            print(f\"Error importing tasks: {e}\")\n            return False\n\n    # ==================== CRUD OPERATIONS ====================\n\n    def add_task(\n        self,\n        title: str,\n        description: str = \"\",\n        priority: str = \"medium\",\n        due_date: Optional[str] = None,\n        tags: Optional[List[str]] = None,\n    ) -> TodoItem:\n        \"\"\"Add a new task\"\"\"\n        if not title.strip():\n            raise ValueError(\"Task title cannot be empty\")\n\n        task = TodoItem(\n            title=title,\n            description=description,\n            priority=priority,\n            due_date=due_date,\n            tags=tags or [],\n        )\n        self.tasks[task.id] = task\n        self.save_to_storage()\n        return task\n\n    def get_task(self, task_id: str) -> Optional[TodoItem]:\n        \"\"\"Get a task by ID\"\"\"\n        return self.tasks.get(task_id)\n\n    def get_all_tasks(self) -> List[TodoItem]:\n        \"\"\"Get all tasks\"\"\"\n        return list(self.tasks.values())\n\n    def update_task(\n        self,\n        task_id: str,\n        title: Optional[str] = None,\n        description: Optional[str] = None,\n        priority: Optional[str] = None,\n        due_date: Optional[str] = None,\n        tags: Optional[List[str]] = None,\n    ) -> bool:\n        \"\"\"Update a task\"\"\"\n        if task_id not in self.tasks:\n            return False\n\n        task = self.tasks[task_id]\n        if title is not None:\n            task.title = title\n        if description is not None:\n            task.description = description\n        if priority is not None:\n            task.priority = priority.lower()\n        if due_date is not None:\n            task.due_date = due_date\n        if tags is not None:\n            task.tags = tags\n\n        self.save_to_storage()\n        return True\n\n    def delete_task(self, task_id: str) -> bool:\n        \"\"\"Delete a task\"\"\"\n        if task_id in self.tasks:\n            del self.tasks[task_id]\n            self.save_to_storage()\n            return True\n        return False\n\n    def delete_all_tasks(self) -> int:\n        \"\"\"Delete all tasks\"\"\"\n        count = len(self.tasks)\n        self.tasks.clear()\n        self.save_to_storage()\n        return count\n\n    # ==================== TASK MANAGEMENT ====================\n\n    def complete_task(self, task_id: str) -> bool:\n        \"\"\"Mark task as completed\"\"\"\n        if task_id not in self.tasks:\n            return False\n\n        self.tasks[task_id].mark_complete()\n        self.save_to_storage()\n        return True\n\n    def uncomplete_task(self, task_id: str) -> bool:\n        \"\"\"Mark task as incomplete\"\"\"\n        if task_id not in self.tasks:\n            return False\n\n        self.tasks[task_id].mark_incomplete()\n        self.save_to_storage()\n        return True\n\n    def toggle_task(self, task_id: str) -> bool:\n        \"\"\"Toggle task completion status\"\"\"\n        if task_id not in self.tasks:\n            return False\n\n        task = self.tasks[task_id]\n        if task.completed:\n            task.mark_incomplete()\n        else:\n            task.mark_complete()\n        self.save_to_storage()\n        return True\n\n    # ==================== FILTERING & SEARCHING ====================\n\n    def get_completed_tasks(self) -> List[TodoItem]:\n        \"\"\"Get all completed tasks\"\"\"\n        return [task for task in self.tasks.values() if task.completed]\n\n    def get_pending_tasks(self) -> List[TodoItem]:\n        \"\"\"Get all pending (incomplete) tasks\"\"\"\n        return [task for task in self.tasks.values() if not task.completed]\n\n    def get_tasks_by_priority(self, priority: str) -> List[TodoItem]:\n        \"\"\"Get tasks by priority level\"\"\"\n        priority = priority.lower()\n        return [\n            task for task in self.tasks.values()\n            if task.priority == priority and not task.completed\n        ]\n\n    def get_tasks_by_tag(self, tag: str) -> List[TodoItem]:\n        \"\"\"Get tasks by tag\"\"\"\n        return [\n            task for task in self.tasks.values()\n            if tag.lower() in [t.lower() for t in task.tags]\n        ]\n\n    def search_tasks(self, query: str) -> List[TodoItem]:\n        \"\"\"Search tasks by title or description\"\"\"\n        query_lower = query.lower()\n        return [\n            task\n            for task in self.tasks.values()\n            if query_lower in task.title.lower()\n            or query_lower in task.description.lower()\n        ]\n\n    def get_overdue_tasks(self) -> List[TodoItem]:\n        \"\"\"Get tasks that are overdue\"\"\"\n        today = datetime.now().date().isoformat()\n        return [\n            task\n            for task in self.tasks.values()\n            if task.due_date and task.due_date < today and not task.completed\n        ]\n\n    def get_tasks_due_today(self) -> List[TodoItem]:\n        \"\"\"Get tasks due today\"\"\"\n        today = datetime.now().date().isoformat()\n        return [\n            task\n            for task in self.tasks.values()\n            if task.due_date == today and not task.completed\n        ]\n\n    def get_tasks_due_soon(self, days: int = 7) -> List[TodoItem]:\n        \"\"\"Get tasks due within N days\"\"\"\n        from datetime import timedelta\n\n        today = datetime.now().date()\n        future = (today + timedelta(days=days)).isoformat()\n        return [\n            task\n            for task in self.tasks.values()\n            if task.due_date\n            and today.isoformat() <= task.due_date <= future\n            and not task.completed\n        ]\n\n    # ==================== STATISTICS ====================\n\n    def get_statistics(self) -> Dict[str, Any]:\n        \"\"\"Get task statistics\"\"\"\n        total = len(self.tasks)\n        completed = len(self.get_completed_tasks())\n        pending = len(self.get_pending_tasks())\n\n        priority_counts = {}\n        for priority in [\"low\", \"medium\", \"high\", \"urgent\"]:\n            priority_counts[priority] = len(self.get_tasks_by_priority(priority))\n\n        return {\n            \"total_tasks\": total,\n            \"completed\": completed,\n            \"pending\": pending,\n            \"completion_rate\": f\"{(completed / total * 100):.1f}%\" if total > 0 else \"0%\",\n            \"overdue\": len(self.get_overdue_tasks()),\n            \"due_today\": len(self.get_tasks_due_today()),\n            \"priority_breakdown\": priority_counts,\n        }\n\n    def clear_completed_tasks(self) -> int:\n        \"\"\"Remove all completed tasks\"\"\"\n        completed_ids = [task.id for task in self.get_completed_tasks()]\n        for task_id in completed_ids:\n            self.delete_task(task_id)\n        return len(completed_ids)\n\n    # ==================== DISPLAY ====================\n\n    def display_all_tasks(self, show_completed: bool = True) -> None:\n        \"\"\"Display all tasks in a formatted way\"\"\"\n        tasks = self.get_all_tasks()\n\n        if not tasks:\n            print(\"\\n📝 No tasks found!\\n\")\n            return\n\n        if not show_completed:\n            tasks = self.get_pending_tasks()\n\n        print(\"\\n\" + \"=\" * 80)\n        print(\"📋 TO-DO LIST\")\n        print(\"=\" * 80)\n\n        for i, task in enumerate(tasks, 1):\n            print(f\"{i}. {task}\")\n            if task.description:\n                print(f\"   Description: {task.description}\")\n            print(f\"   ID: {task.id}\")\n            print()\n\n        print(\"=\" * 80)\n\n    def display_statistics(self) -> None:\n        \"\"\"Display task statistics\"\"\"\n        stats = self.get_statistics()\n\n        print(\"\\n\" + \"=\" * 60)\n        print(\"📊 TASK STATISTICS\")\n        print(\"=\" * 60)\n        print(f\"Total Tasks: {stats['total_tasks']}\")\n        print(f\"Completed: {stats['completed']}\")\n        print(f\"Pending: {stats['pending']}\")\n        print(f\"Completion Rate: {stats['completion_rate']}\")\n        print(f\"Overdue: {stats['overdue']}\")\n        print(f\"Due Today: {stats['due_today']}\")\n        print(\"\\nPriority Breakdown:\")\n        for priority, count in stats[\"priority_breakdown\"].items():\n            print(f\"  {priority.capitalize()}: {count}\")\n        print(\"=\" * 60 + \"\\n\")\n\n\ndef interactive_todo_app():\n    \"\"\"Run the to-do list application in interactive mode\"\"\"\n    todo_list = TodoList()\n\n    print(\"\\n\" + \"=\" * 60)\n    print(\"✅ WELCOME TO TO-DO LIST APPLICATION\")\n    print(\"=\" * 60)\n    print(\"Type 'help' for available commands or 'quit' to exit\\n\")\n\n    while True:\n        try:\n            user_input = input(\"\\n> \").strip()\n\n            if not user_input:\n                continue\n\n            command = user_input.lower().split()\n            cmd = command[0]\n\n            # HELP\n            if cmd == \"help\":\n                print(\n                    \"\"\"\n╔════════════════════════════════════════════════════════════╗\n║              AVAILABLE COMMANDS                            ║\n╠════════════════════════════════════════════════════════════╣\n║ BASIC OPERATIONS:                                         ║\n║  add <title>              - Add a new task                 ║\n║  list                     - Display all tasks              ║\n║  list-pending             - Show only pending tasks        ║\n║  list-completed           - Show only completed tasks      ║\n║                                                            ║\n║ TASK MANAGEMENT:                                          ║\n║  complete <id>            - Mark task as completed         ║\n║  uncomplete <id>          - Mark task as incomplete        ║\n║  toggle <id>              - Toggle task status             ║\n║  delete <id>              - Delete a task                  ║\n║  delete-all               - Delete all tasks               ║\n║  clear-completed          - Remove completed tasks         ║\n║                                                            ║\n║ FILTERING & SEARCH:                                       ║\n║  priority <level>         - Get tasks by priority          ║\n║  tag <name>               - Get tasks by tag               ║\n║  search <query>           - Search tasks                   ║\n║  overdue                  - Show overdue tasks             ║\n║  today                    - Show tasks due today           ║\n║  week                     - Show tasks due this week       ║\n║                                                            ║\n║ INFORMATION:                                              ║\n║  stats                    - Show statistics                ║\n║  export <filename>        - Export tasks to file           ║\n║  import <filename>        - Import tasks from file         ║\n║  quit                     - Exit application               ║\n╚════════════════════════════════════════════════════════════╝\n                \"\"\"\n                )\n\n            # ADD\n            elif cmd == \"add\":\n                title = \" \".join(command[1:]) if len(command) > 1 else \"\"\n                if not title:\n                    title = input(\"  Task title: \").strip()\n\n                description = input(\"  Description (optional): \").strip()\n                priority = input(\"  Priority [low/medium/high/urgent] (default: medium): \").strip()\n                due_date = input(\"  Due date (YYYY-MM-DD, optional): \").strip()\n                tags_input = input(\"  Tags (comma-separated, optional): \").strip()\n\n                priority = priority or \"medium\"\n                tags = [t.strip() for t in tags_input.split(\",\")] if tags_input else []\n\n                try:\n                    task = todo_list.add_task(\n                        title=title,\n                        description=description,\n                        priority=priority,\n                        due_date=due_date or None,\n                        tags=tags,\n                    )\n                    print(f\"\\n✅ Task added: {task.title} (ID: {task.id})\")\n                except ValueError as e:\n                    print(f\"❌ Error: {e}\")\n\n            # LIST\n            elif cmd == \"list\":\n                todo_list.display_all_tasks()\n\n            elif cmd == \"list-pending\":\n                pending = todo_list.get_pending_tasks()\n                if not pending:\n                    print(\"\\n✅ No pending tasks!\")\n                else:\n                    print(\"\\n\" + \"=\" * 60)\n                    print(\"📝 PENDING TASKS\")\n                    print(\"=\" * 60)\n                    for i, task in enumerate(pending, 1):\n                        print(f\"{i}. {task}\")\n                    print()\n\n            elif cmd == \"list-completed\":\n                completed = todo_list.get_completed_tasks()\n                if not completed:\n                    print(\"\\n📭 No completed tasks yet!\")\n                else:\n                    print(\"\\n\" + \"=\" * 60)\n                    print(\"✅ COMPLETED TASKS\")\n                    print(\"=\" * 60)\n                    for i, task in enumerate(completed, 1):\n                        print(f\"{i}. {task}\")\n                    print()\n\n            # TASK MANAGEMENT\n            elif cmd == \"complete\":\n                if len(command) < 2:\n                    task_id = input(\"  Enter task ID: \").strip()\n                else:\n                    task_id = command[1]\n\n                if todo_list.complete_task(task_id):\n                    print(\"✅ Task marked as completed\")\n                else:\n                    print(f\"❌ Task not found: {task_id}\")\n\n            elif cmd == \"uncomplete\":\n                if len(command) < 2:\n                    task_id = input(\"  Enter task ID: \").strip()\n                else:\n                    task_id = command[1]\n\n                if todo_list.uncomplete_task(task_id):\n                    print(\"↩️  Task marked as incomplete\")\n                else:\n                    print(f\"❌ Task not found: {task_id}\")\n\n            elif cmd == \"toggle\":\n                if len(command) < 2:\n                    task_id = input(\"  Enter task ID: \").strip()\n                else:\n                    task_id = command[1]\n\n                if todo_list.toggle_task(task_id):\n                    task = todo_list.get_task(task_id)\n                    status = \"completed\" if task.completed else \"incomplete\"\n                    print(f\"🔄 Task toggled to {status}\")\n                else:\n                    print(f\"❌ Task not found: {task_id}\")\n\n            elif cmd == \"delete\":\n                if len(command) < 2:\n                    task_id = input(\"  Enter task ID: \").strip()\n                else:\n                    task_id = command[1]\n\n                if todo_list.delete_task(task_id):\n                    print(\"🗑️  Task deleted\")\n                else:\n                    print(f\"❌ Task not found: {task_id}\")\n\n            elif cmd == \"delete-all\":\n                confirm = input(\"  ⚠️  Are you sure? (yes/no): \").strip().lower()\n                if confirm == \"yes\":\n                    count = todo_list.delete_all_tasks()\n                    print(f\"🗑️  Deleted {count} tasks\")\n                else:\n                    print(\"❌ Cancelled\")\n\n            elif cmd == \"clear-completed\":\n                count = todo_list.clear_completed_tasks()\n                print(f\"✨ Cleared {count} completed tasks\")\n\n            # FILTERING & SEARCH\n            elif cmd == \"priority\":\n                if len(command) < 2:\n                    priority = input(\"  Enter priority [low/medium/high/urgent]: \").strip()\n                else:\n                    priority = command[1]\n\n                tasks = todo_list.get_tasks_by_priority(priority)\n                if not tasks:\n                    print(f\"\\n❌ No {priority} priority tasks found\")\n                else:\n                    print(f\"\\n{priority.upper()} PRIORITY TASKS:\")\n                    for i, task in enumerate(tasks, 1):\n                        print(f\"{i}. {task}\")\n                    print()\n\n            elif cmd == \"tag\":\n                if len(command) < 2:\n                    tag = input(\"  Enter tag name: \").strip()\n                else:\n                    tag = command[1]\n\n                tasks = todo_list.get_tasks_by_tag(tag)\n                if not tasks:\n                    print(f\"\\n❌ No tasks with tag '{tag}' found\")\n                else:\n                    print(f\"\\nTASKS WITH TAG '#{tag}':\")\n                    for i, task in enumerate(tasks, 1):\n                        print(f\"{i}. {task}\")\n                    print()\n\n            elif cmd == \"search\":\n                if len(command) < 2:\n                    query = input(\"  Enter search query: \").strip()\n                else:\n                    query = \" \".join(command[1:])\n\n                tasks = todo_list.search_tasks(query)\n                if not tasks:\n                    print(f\"\\n❌ No tasks matching '{query}' found\")\n                else:\n                    print(f\"\\nSEARCH RESULTS FOR '{query}':\")\n                    for i, task in enumerate(tasks, 1):\n                        print(f\"{i}. {task}\")\n                    print()\n\n            elif cmd == \"overdue\":\n                tasks = todo_list.get_overdue_tasks()\n                if not tasks:\n                    print(\"\\n✅ No overdue tasks!\")\n                else:\n                    print(\"\\n\" + \"=\" * 60)\n                    print(\"⏰ OVERDUE TASKS\")\n                    print(\"=\" * 60)\n                    for i, task in enumerate(tasks, 1):\n                        print(f\"{i}. {task}\")\n                    print()\n\n            elif cmd == \"today\":\n                tasks = todo_list.get_tasks_due_today()\n                if not tasks:\n                    print(\"\\n✅ No tasks due today!\")\n                else:\n                    print(\"\\n\" + \"=\" * 60)\n                    print(\"📅 DUE TODAY\")\n                    print(\"=\" * 60)\n                    for i, task in enumerate(tasks, 1):\n                        print(f\"{i}. {task}\")\n                    print()\n\n            elif cmd == \"week\":\n                tasks = todo_list.get_tasks_due_soon(7)\n                if not tasks:\n                    print(\"\\n✅ No tasks due this week!\")\n                else:\n                    print(\"\\n\" + \"=\" * 60)\n                    print(\"📆 DUE THIS WEEK\")\n                    print(\"=\" * 60)\n                    for i, task in enumerate(tasks, 1):\n                        print(f\"{i}. {task}\")\n                    print()\n\n            # STATISTICS\n            elif cmd == \"stats\":\n                todo_list.display_statistics()\n\n            # IMPORT/EXPORT\n            elif cmd == \"export\":\n                if len(command) < 2:\n                    filename = input(\"  Enter filename: \").strip()\n                else:\n                    filename = command[1]\n\n                if todo_list.export_to_file(filename):\n                    print(f\"✅ Tasks exported to {filename}\")\n                else:\n                    print(f\"❌ Failed to export tasks\")\n\n            elif cmd == \"import\":\n                if len(command) < 2:\n                    filename = input(\"  Enter filename: \").strip()\n                else:\n                    filename = command[1]\n\n                if todo_list.import_from_file(filename):\n                    print(f\"✅ Tasks imported from {filename}\")\n                else:\n                    print(f\"❌ Failed to import tasks\")\n\n            # QUIT\n            elif cmd == \"quit\":\n                print(\"\\n👋 Goodbye! Your tasks have been saved.\\n\")\n                break\n\n            else:\n                print(f\"❌ Unknown command: {cmd}. Type 'help' for available commands.\")\n\n        except KeyboardInterrupt:\n            print(\"\\n\\n👋 Goodbye! Your tasks have been saved.\\n\")\n            break\n        except Exception as e:\n            print(f\"❌ Error: {e}\")\n\n\nif __name__ == \"__main__\":\n    interactive_todo_app()\n"